css:
.vbes-faq {
  max-width: 720px;
  margin: 0 auto;
  padding: 64px 24px;
}
.vbes-faq__heading {
  font-size: 2rem;
  font-weight: 700;
  text-align: center;
  margin: 0 0 40px;
}
.vbes-faq__item {
  border-bottom: 1px solid #e0e0e0;
}
.vbes-faq__question {
  padding: 20px 0;
  font-size: 1.1rem;
  font-weight: 600;
  cursor: pointer;
  list-style: none;
  display: flex;
  justify-content: space-between;
  align-items: center;
}
.vbes-faq__question::-webkit-details-marker {
  display: none;
}
.vbes-faq__question::after {
  content: '+';
  font-size: 1.5rem;
  font-weight: 300;
  color: #999;
  transition: transform 0.2s;
}
details[open] .vbes-faq__question::after {
  content: '\2212';
}
.vbes-faq__answer {
  padding: 0 0 20px;
  font-size: 0.95rem;
  line-height: 1.7;
  color: #555;
}
